export let CONTENT_BASE_URL = `${CDN_BASE}/CreativeWorkshop/source/`;
export const CONFIG_KEY = 'fate_updater_config_v2';

// 切换 CDN 路径的函数
export const switchCDN = (index: number) => {
  if (index >= 0 && index < CDN_BASES.length) {
    CDN_BASE = CDN_BASES[index];
    CATALOG_URL = `${CDN_BASE}/CreativeWorkshop/catalog.json`;
    CONTENT_BASE_URL = `${CDN_BASE}/CreativeWorkshop/source/`;
    console.info(`已切换到 CDN 路径: ${CDN_BASE}`);
  }
};

