// ==================== 统一界面 ====================
// 避免循环依赖，使用动态导入
import { closeModal, getConfig, saveConfig, showModal } from './utils';
import { deleteWorldbookEntries, deployWorldbookEntry, getCurrentWorldbook, getWorldbookEntries } from './worldbook';

// 统一数据结构
interface TavernItem {
  id: string; // 对应世界书中的uid或目录中的name
  name: string; // 条目名称
  type: ItemType; // 项目类型：'system' | 'character' | 'event' | 'extension'
  tags: string[]; // 用于筛选和搜索的标签
  metadata: Record<string, any>; // 其他元数据（author、updateTime、description等）
  content: string; // 要部署到世界书的内容
  installed: boolean; // 是否已安装到当前世界书
}

type ItemType = 'system' | 'character' | 'event' | 'extension';

// 从在线CDN获取目录数据
import { CATALOG_URL, CDN_BASE, CDN_BASES, CONTENT_BASE_URL, switchCDN } from './config';

// 记录滑块位置的变量
let scrollPosition = 0;

const fetchCatalog = async (): Promise<Record<string, any>> => {
  let lastError: Error | null = null;

  for (let i = 0; i < CDN_BASES.length; i++) {
    try {
      switchCDN(i);
      const response = await fetch(CATALOG_URL, { cache: 'no-cache' });
      if (response.ok) {
        console.info(`成功从 CDN ${i + 1} 加载目录: ${CDN_BASE}`);
        return await response.json();
      }
    } catch (error) {
      lastError = error as Error;
      console.warn(`CDN ${i + 1} 加载失败，尝试下一个 CDN:`, error);
    }
  }

  console.error('所有 CDN 都加载目录失败');
  toastr.error('加载目录失败，所有 CDN 均不可用');
  return {};
};

// 获取项目内容
const fetchItemContent = async (itemName: string): Promise<string> => {
  let lastError: Error | null = null;

  for (let i = 0; i < CDN_BASES.length; i++) {
    try {
      switchCDN(i);
      const response = await fetch(`${CONTENT_BASE_URL}${itemName}.json`);
      if (response.ok) {
        return await response.text();
      }
    } catch (error) {
      lastError = error as Error;
      console.warn(`CDN ${i + 1} 加载项目内容失败，尝试下一个 CDN:`, error);
    }
  }

  console.error(`所有 CDN 都加载项目 ${itemName} 内容失败`);
  return '获取内容失败';
};

// 将目录项转换为统一数据结构
const convertToTavernItem = async (name: string, data: any, installedItems: any[]): Promise<TavernItem> => {
  // 确定项目类型
  let type: ItemType = 'system'; // 默认类型
  const tags = Array.isArray(data.tag) ? data.tag : data.tag ? [data.tag] : [];

  if (tags.includes('角色')) type = 'character';
  else if (tags.includes('事件')) type = 'event';
  else if (tags.includes('扩展')) type = 'extension';
  else if (tags.includes('系统')) type = 'system';

  // 检查是否已安装 - 需要检查该项目的任何一个条目是否存在于世界书中
  let isInstalled = false;
  try {
    const response = await fetch(`${CONTENT_BASE_URL}${name}.json`);
    if (response.ok) {
      const itemData = await response.json();
      const entries = Object.values(itemData.entries || {}) as any[];
      // 检查项目的任何一个条目是否存在于世界书中
      isInstalled = entries.some(entry => {
        const entryComment = entry.comment || entry.name;
        return installedItems.some(installedItem => {
          const installedComment = installedItem.comment || installedItem.name;
          return installedComment === entryComment;
        });
      });
    }
  } catch (error) {
    console.error(`Error checking if item ${name} is installed:`, error);
  }

  return {
    id: name,
    name: name,
    type,
    tags,
    metadata: {
      author: data.author || '未知',
      updateTime: data.updateTime || '未知',
      description: data.description || '暂无简介',
    },
    content: '',
    installed: isInstalled,
  };
};

// 获取所有可部署项目（仅获取基本信息，不获取详细内容）
const getAllTavernItems = async (): Promise<TavernItem[]> => {
  const catalog = await fetchCatalog();
  const worldbookEntries = await getAllWorldbookEntries();
  return await Promise.all(
    Object.entries(catalog).map(async ([name, data]) => await convertToTavernItemBasic(name, data, worldbookEntries)),
  );
};

// 将目录项转换为统一数据结构（仅获取基本信息）
const convertToTavernItemBasic = async (name: string, data: any, installedItems: any[]): Promise<TavernItem> => {
  // 确定项目类型
  let type: ItemType = 'system'; // 默认类型
  const tags = Array.isArray(data.tag) ? data.tag : data.tag ? [data.tag] : [];

  if (tags.includes('角色')) type = 'character';
  else if (tags.includes('事件')) type = 'event';
  else if (tags.includes('扩展')) type = 'extension';
  else if (tags.includes('系统')) type = 'system';

  // 检查是否已安装 - 通过 extra.fate_project_name 字段精确匹配
  // 部署时会在条目的 extra 中存储项目名称，这样可以实现精确匹配
  const isInstalled = installedItems.some(installedItem => {
    const projectName = installedItem.extra?.fate_project_name || '';
    return projectName === name;
  });

  return {
    id: name,
    name: name,
    type,
    tags,
    metadata: {
      author: data.author || '未知',
      updateTime: data.updateTime || '未知',
      description: data.description || '暂无简介',
    },
    content: '', // 暂时为空，只在需要时获取
    installed: isInstalled,
  };
};

// 获取项目详细内容（仅在需要时调用）
const fetchItemDetail = async (item: TavernItem): Promise<TavernItem> => {
  if (!item.content) {
    item.content = await fetchItemContent(item.id);
  }
  return item;
};

// 从世界书获取所有条目
const getAllWorldbookEntries = async (): Promise<any[]> => {
  const worldbook = getCurrentWorldbook('current');
  return (await getWorldbookEntries(worldbook.primary)) || [];
};

// 根据条目类型获取对应的中文标签
const getTypeLabel = (type: ItemType): string => {
  const labels: Record<ItemType, string> = {
    system: '系统',
    character: '角色',
    event: '事件',
    extension: '扩展',
  };
  return labels[type];
};

// 根据规则重命名条目名称
const renameEntry = (entryName: string, item: TavernItem): string => {
  if (item.type === 'system') {
    // "系统"：检测条目前面是否有"命定系统-"的前缀，没有则添加上
    if (!entryName.startsWith('命定系统-')) {
      return `命定系统-${entryName}`;
    }
    return entryName;
  } else {
    // "角色，事件，扩展"：检测条目前面是否有"[DLC]"的前缀，没有则添加前缀"[DLC][$1][$2]"
    // $1为"角色，事件，扩展"三选一，即对应的tag；$2为{item.name}
    if (!entryName.startsWith('[DLC]')) {
      const typeLabel = getTypeLabel(item.type);
      return `[DLC][${typeLabel}][${item.name}]${entryName}`;
    }
    return entryName;
  }
};

// 部署项目
const deployItem = async (item: TavernItem) => {
  try {
    toastr.info(`正在部署 ${item.name}...`, '', { timeOut: 0 });
    const worldbook = getCurrentWorldbook('current');

    // 获取项目内容
    const response = await fetch(`${CONTENT_BASE_URL}${item.id}.json`);
    if (!response.ok) {
      throw new Error(`Failed to fetch content for ${item.name}: ${response.status}`);
    }
    const data = await response.json();

    // 遍历所有条目并部署
    const entries = Object.values(data.entries || {}) as any[];
    for (const entry of entries) {
      // 根据规则重命名条目
      const originalName = entry.comment || '无标题';
      const renamedName = renameEntry(originalName, item);

      // 构建条目配置（与 worldbook.ts 中 deployWorldbookEntry 期望的格式一致）
      const entryConfig = {
        name: renamedName,
        enabled: !entry.disable,
        constant: entry.constant,
        selective: entry.selective,
        selectiveLogic: entry.selectiveLogic,
        key: entry.key,
        keysecondary: entry.keysecondary,
        scanDepth: entry.scanDepth,
        depth: entry.depth,
        displayIndex: entry.displayIndex,
        role: entry.role,
        excludeRecursion: entry.excludeRecursion,
        preventRecursion: entry.preventRecursion,
        delayUntilRecursion: entry.delayUntilRecursion,
        sticky: entry.sticky,
        cooldown: entry.cooldown,
        delay: entry.delay,
        useProbability: entry.useProbability,
        probability: entry.probability,
        comment: entry.comment || item.metadata.description,
      };

      await deployWorldbookEntry(worldbook.primary, renamedName, entryConfig, entry.content, item.name);
    }

    toastr.clear();
    toastr.success(`成功部署 ${item.name} (共${entries.length}个条目)`, '项目部署完成');

    // 更新项目安装状态
    item.installed = true;
  } catch (e: any) {
    toastr.clear();
    toastr.error(`部署失败: ${e.message}`);
  }
};

// 卸载项目
const uninstallItem = async (item: TavernItem) => {
  try {
    toastr.info(`正在卸载 ${item.name}...`, '', { timeOut: 0 });
    const worldbook = getCurrentWorldbook('current');

    // 通过 extra.fate_project_name 字段匹配要卸载的条目
    const result = await deleteWorldbookEntries(
      worldbook.primary,
      (existingEntry: any) => existingEntry.extra?.fate_project_name === item.name,
    );

    const deletedCount = result.deleted_entries?.length || 0;
    if (deletedCount > 0) {
      toastr.clear();
      toastr.success(`成功卸载 ${item.name} (共${deletedCount}个条目)`, '项目卸载完成');
    } else {
      // 如果没有找到通过 extra 字段匹配的条目，尝试通过项目名称作为 comment 的一部分匹配（旧方式兼容）
      const fallbackResult = await deleteWorldbookEntries(worldbook.primary, (existingEntry: any) => {
        // 尝试匹配 comment 字段中包含项目名称的条目（用于兼容旧数据）
        const comment = existingEntry.comment || '';
        return comment.includes(item.name) || existingEntry.name === item.name;
      });
      const fallbackCount = fallbackResult.deleted_entries?.length || 0;
      toastr.clear();
      if (fallbackCount > 0) {
        toastr.success(`成功卸载 ${item.name} (共${fallbackCount}个条目)`, '项目卸载完成');
      } else {
        toastr.warning(`未找到已安装的 ${item.name} 条目`, '卸载完成');
      }
    }

    // 更新项目安装状态
    item.installed = false;
  } catch (e: any) {
    toastr.clear();
    toastr.error(`卸载失败: ${e.message}`);
  }
};

// 渲染项目卡片
const renderItemCard = (item: TavernItem, config: any): string => {
  const typeLabels = {
    system: { label: '系统', color: 'var(--color-system)', class: 'system' },
    character: { label: '角色', color: 'var(--color-character)', class: 'character' },
    event: { label: '事件', color: 'var(--color-event)', class: 'event' },
    extension: { label: '扩展', color: 'var(--color-extension)', class: 'extension' },
  };

  const typeInfo = typeLabels[item.type];
  const tagsHtml = item.tags
    .map(
      tag => `
    <span class="fate-tag">
      ${tag}
    </span>
  `,
    )
    .join('');

  return `
    <div class="fate-card ${item.type}-card" data-id="${item.id}" data-search="${(item.name + ' ' + item.metadata.author + ' ' + item.metadata.updateTime + ' ' + item.metadata.description).toLowerCase()}"
         style="height: auto; min-height: 270px;">
      <div class="fate-card-header">
        <span class="fate-type-label ${typeInfo.class}" style="background: ${typeInfo.color}; color: white; padding: 4px 12px; border-radius: 20px; font-size: 0.75rem; font-weight: 600; letter-spacing: 0.3px;">
          <i class="fas fa-${item.type === 'system' ? 'cog' : item.type === 'character' ? 'user' : item.type === 'event' ? 'calendar-alt' : 'puzzle-piece'}" style="margin-right:4px;"></i>${typeInfo.label}
        </span>
        ${
          item.installed
            ? `
          <span class="fate-installed-badge">
            <i class="fas fa-check-circle"></i> 已安装
          </span>
        `
            : ''
        }
      </div>
      <div class="fate-card-title">
        ${item.name}
      </div>
      <div class="fate-card-sep"></div>
      <div class="fate-card-info">
        <div class="fate-info-row"><span style="opacity:0.6;"><i class="fas fa-user-edit" style="margin-right:4px;"></i>作者</span><span class="fate-info-value">${item.metadata.author}</span></div>
        <div class="fate-info-row"><span style="opacity:0.6;"><i class="fas fa-clock" style="margin-right:4px;"></i>更新</span><span class="fate-info-value">${item.metadata.updateTime}</span></div>
      </div>
      <div class="fate-card-tags">${tagsHtml}</div>
      <div class="fate-card-actions">
        <button class="fate-action-btn detail-btn" data-id="${item.id}" title="详情">
          <i class="fas fa-info-circle"></i> 详情
        </button>
        ${
          item.installed
            ? `
          <button class="fate-action-btn uninstall-btn" data-id="${item.id}" title="卸载">
            <i class="fas fa-trash-alt"></i> 卸载
          </button>
        `
            : `
          <button class="fate-action-btn deploy-btn" data-id="${item.id}" title="注入">
            <i class="fas fa-download"></i> 注入
          </button>
        `
        }
      </div>
    </div>
  `;
};

