import { CONFIG_KEY, DEFAULT_CONFIG } from './config';

// ==================== 工具函数 ====================
export const adjustColor = (color: string, amount: number): string => {
  let hex = color.replace(/^#/, '');
  if (hex.length === 3) {
    hex = hex
      .split('')
      .map(c => c + c)
      .join('');
  }
  const num = parseInt(hex, 16);
  let r = (num >> 16) + amount;
  let g = ((num >> 8) & 0xff) + amount;
  let b = (num & 0xff) + amount;
  r = Math.max(0, Math.min(255, r));
  g = Math.max(0, Math.min(255, g));
  b = Math.max(0, Math.min(255, b));
  return `#${((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1)}`;
};

export const getConfig = (): typeof DEFAULT_CONFIG => {
  try {
    const stored = localStorage.getItem(CONFIG_KEY);
    if (stored) return { ...DEFAULT_CONFIG, ...JSON.parse(stored) };
  } catch (e) {
    // ignore
  }
  return { ...DEFAULT_CONFIG };
};

export const saveConfig = (cfg: typeof DEFAULT_CONFIG): void => {
  localStorage.setItem(CONFIG_KEY, JSON.stringify(cfg));
};

export const isLightColor = (hex: string): boolean => {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return (r * 299 + g * 587 + b * 114) / 1000 > 155;
};

// ==================== 模态框管理 ====================
export const closeModal = (): void => {
  const doc = window.top?.document || document;
  const modals = doc.querySelectorAll('.fate-modal-overlay');
  if (modals.length > 0) {
    modals[modals.length - 1].remove();
  }
};
(window as any).closeCustomModal = closeModal;

