// ==================== 上传界面 ====================
import { CLOUDFLARE_API, getApiBaseUrl } from './config';
import { getConfig, injectGlobalStyles } from './utils';

// 处理 OAuth 回调 URL 参数（当回调页面刷新父窗口时会被调用）
const handleOAuthCallbackFromUrl = (): boolean => {
  const hash = window.location.hash;
  const params = new URLSearchParams(window.location.search);

  // 检查是否是 OAuth 成功回调
  if (hash === '#oauth-success' || params.get('token')) {
    console.info('检测到 OAuth 回调参数');

    const token = params.get('token');
    const userStr = params.get('user');

    if (token && userStr) {
      try {
        const user = JSON.parse(decodeURIComponent(userStr));
        console.info('从 URL 参数解析到用户信息:', user);

        // 保存 Token 信息
        localStorage.setItem(CLOUDFLARE_API.tokenKey, token);
        localStorage.setItem(CLOUDFLARE_API.userKey, JSON.stringify(user));

        // 清除 URL 参数
        window.history.replaceState(null, '', window.location.pathname);

        toastr.success('登录成功！');
        return true;
      } catch (e) {
        console.error('解析 OAuth 回调参数失败:', e);
      }
    }
  }
  return false;
};

// 初始化时检查 URL 参数
if (typeof window !== 'undefined') {
  handleOAuthCallbackFromUrl();
}

// 用户信息
interface User {
  id: string;
  username: string;
  avatar: string;
  avatarUrl: string;
  isAdmin: boolean;
}

// 项目信息
interface Project {
  id: string;
  name: string;
  description: string;
  version: string;
  authorId: string;
  authorName: string;
  authorAvatar: string;
  status: 'pending' | 'approved' | 'rejected';
  downloadUrl: string;
  fileSize: number;
  tags: string[];
  coverImage: string;
  createdAt: string;
  updatedAt: string;
  rejectReason?: string;
}

// 当前登录用户
let currentUser: User | null = null;

// 获取当前用户
export const getCurrentUser = (): User | null => {
  try {
    const stored = localStorage.getItem(CLOUDFLARE_API.userKey);
    if (stored) {
      currentUser = JSON.parse(stored);
      return currentUser;
    }
  } catch (e) {
    // ignore
  }
  return null;
};

// 保存用户信息
const saveUser = (user: User | null): void => {
  currentUser = user;
  if (user) {
    localStorage.setItem(CLOUDFLARE_API.userKey, JSON.stringify(user));
  } else {
    localStorage.removeItem(CLOUDFLARE_API.userKey);
  }
};

// 获取 Token
const getToken = (): string | null => {
  return localStorage.getItem(CLOUDFLARE_API.tokenKey);
};

// 保存 Token
const saveToken = (token: string): void => {
  localStorage.setItem(CLOUDFLARE_API.tokenKey, token);
};

// 清除 Token
const clearToken = (): void => {
  localStorage.removeItem(CLOUDFLARE_API.tokenKey);
  saveUser(null);
};

// API 请求封装
const apiRequest = async <T>(endpoint: string, options: RequestInit = {}): Promise<T> => {
  const baseUrl = getApiBaseUrl();
  const token = getToken();

  const headers: Record<string, string> = {
    ...((options.headers as Record<string, string>) || {}),
  };

  if (token) {
    headers['Authorization'] = `Bearer ${token}`;
  }

  console.info(`API请求: ${baseUrl}${endpoint}`);

  const response = await fetch(`${baseUrl}${endpoint}`, {
    ...options,
    headers,
  });

  if (response.status === 401) {
    // Token 过期，清除登录状态
    clearToken();
    throw new Error('登录已过期，请重新登录');
  }

  // 尝试解析 JSON 响应
  let data;
  try {
    data = await response.json();
  } catch (e) {
    // 如果不是 JSON 响应，尝试获取文本
    const text = await response.text();
    console.error('API 响应不是 JSON:', text.substring(0, 500));
    throw new Error(`服务器错误: ${response.status} - ${text.substring(0, 100)}`);
  }

  if (!response.ok) {
    throw new Error(data.error || data.message || `请求失败: ${response.status}`);
  }

  return data;
};

// 获取登录 URL
export const getLoginUrl = async (): Promise<{ url: string; state: string }> => {
  const data = await apiRequest<{ url: string; state: string }>('/api/auth/login', {
    method: 'GET',
  });
  return data;
};

// 处理 OAuth 回调
export const handleOAuthCallback = async (code: string): Promise<User> => {
  const baseUrl = getApiBaseUrl();
  const token = getToken();

  const headers: Record<string, string> = {
    Accept: 'application/json',
  };

  if (token) {
    headers['Authorization'] = `Bearer ${token}`;
  }

  const response = await fetch(`${baseUrl}/api/auth/callback?code=${code}&format=json`, {
    method: 'GET',
    headers,
  });

  // 尝试解析 JSON 响应
  let data;
  try {
    data = await response.json();
  } catch (e) {
    // 如果不是 JSON 响应，说明后端返回了 HTML（跨域回调页面情况）
    const text = await response.text();
    console.error('回调返回的不是 JSON:', text.substring(0, 500));
    throw new Error('登录失败：无法获取服务器响应');
  }

  if (!response.ok || !data.success || !data.token || !data.user) {
    throw new Error(data.message || '登录失败');
  }

  saveToken(data.token);
  saveUser(data.user);
  return data.user;
};

// 获取当前用户信息
export const fetchCurrentUser = async (): Promise<User | null> => {
  const token = getToken();
  if (!token) return null;

  try {
    const data = await apiRequest<{ user: User | null }>('/api/auth/me', {
      method: 'GET',
    });

    if (data.user) {
      saveUser(data.user);
      return data.user;
    }
  } catch (e) {
    console.error('获取用户信息失败:', e);
  }

  return null;
};

// 登出
export const logout = async (): Promise<void> => {
  try {
    await apiRequest('/api/auth/logout', {
      method: 'POST',
    });
  } catch (e) {
    console.error('登出失败:', e);
  }
  clearToken();
};

// 获取我的项目列表
export const getMyProjects = async (): Promise<Project[]> => {
  const data = await apiRequest<{ success: boolean; projects: Project[] }>('/api/my/projects', {
    method: 'GET',
  });
  return data.projects || [];
};

// 创建项目
export const createProject = async (projectData: {
  name: string;
  description: string;
  version: string;
  tags: string[];
  coverImage?: string;
}): Promise<string> => {
  const data = await apiRequest<{ success: boolean; projectId: string }>('/api/projects', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(projectData),
  });
  return data.projectId;
};

// 上传项目文件
export const uploadProjectFile = async (
  projectId: string,
  file: File,
): Promise<{ downloadUrl: string; fileSize: number }> => {
  const baseUrl = getApiBaseUrl();
  const token = getToken();

  const response = await fetch(`${baseUrl}/api/projects/${projectId}/upload`, {
    method: 'POST',
    headers: {
      Authorization: token ? `Bearer ${token}` : '',
      'Content-Type': file.type || 'application/zip',
    },
    body: file,
  });

  if (!response.ok) {
    const error = await response.json();
    throw new Error(error.error || '上传失败');
  }

  return await response.json();
};

// 删除项目
export const deleteProject = async (projectId: string): Promise<void> => {
  await apiRequest(`/api/projects/${projectId}`, {
    method: 'DELETE',
  });
};

// 更新项目信息
export const updateProject = async (projectId: string, updates: Partial<Project>): Promise<void> => {
  await apiRequest(`/api/projects/${projectId}`, {
    method: 'PUT',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(updates),
  });
};

// 打开上传面板
export const openUploadPanel = async (): Promise<void> => {
  const config = getConfig();
  const targetDoc = window.top?.document || document;

  // 确保全局样式已注入
  injectGlobalStyles(targetDoc);

  // 关闭可能存在的其他模态框
  const existingModal = targetDoc.querySelector('.fate-modal-overlay');
  if (existingModal) {
    existingModal.remove();
  }

  // 创建模态框
  const modalOverlay = targetDoc.createElement('div');
  modalOverlay.className = 'fate-modal-overlay upload-modal';
  Object.assign(modalOverlay.style, {
    position: 'fixed',
    top: '0',
    left: '0',
    width: '100%',
    height: '100%',
    zIndex: '2147483647',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    backgroundColor: 'rgba(0,0,0,0.7)',
    backdropFilter: 'blur(4px)',
  });

  const modalContent = targetDoc.createElement('div');
  modalContent.className = 'fate-modal-content upload-modal-content';
  Object.assign(modalContent.style, {
    backgroundColor: config.bgColor,
    color: config.textColor,
    borderRadius: '16px',
    padding: '24px',
    width: '90%',
    maxWidth: '800px',
    maxHeight: '90vh',
    overflow: 'auto',
  });

  modalOverlay.appendChild(modalContent);
  targetDoc.body.appendChild(modalOverlay);

  // 渲染内容
  await renderUploadContent(modalContent, modalOverlay);

  // 点击外部关闭
  modalOverlay.onclick = (e: MouseEvent) => {
    if (e.target === modalOverlay) {
      modalOverlay.remove();
    }
  };
};

// 渲染上传内容
const renderUploadContent = async (container: HTMLElement, modalOverlay: HTMLElement): Promise<void> => {
  const config = getConfig();

  // 优先尝试从服务器获取用户信息（如果 localStorage 中有 token）
  const token = getToken();
  if (token) {
    try {
      const user = await fetchCurrentUser();
      if (user) {
        // 服务器验证成功，直接显示已登录界面
        renderLoggedInView(container, modalOverlay, user);
        return;
      }
    } catch (e) {
      console.warn('从服务器获取用户信息失败，可能 token 已过期:', e);
      // token 过期，清除本地存储
      clearToken();
    }
  }

  // 如果没有登录或服务器验证失败，显示登录界面
  const user = getCurrentUser();
  if (!user) {
    // 渲染登录界面
    renderLoginView(container, modalOverlay);
  } else {
    // 渲染已登录界面
    renderLoggedInView(container, modalOverlay, user);
  }
};

