// 格式化文件大小
const formatFileSize = (bytes: number): string => {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
};

// 检查 OAuth 回调并处理登录
export const checkAndHandleOAuthCallback = async (): Promise<boolean> => {
  const url = new URL(window.location.href);
  const code = url.searchParams.get('code');
  const state = url.searchParams.get('state');

  if (code) {
    try {
      // 清除 URL 中的参数
      window.history.replaceState({}, '', window.location.pathname);

      // 处理 OAuth 回调
      await handleOAuthCallback(code);
      toastr.success('登录成功！');
      return true;
    } catch (e: any) {
      toastr.error('登录失败: ' + e.message);
    }
  }

  return false;
};

// 初始化上传面板（检查登录状态）
export const initUploadPanel = async (): Promise<void> => {
  // 检查是否有 OAuth 回调
  const handled = await checkAndHandleOAuthCallback();
  if (handled) {
    // 如果处理了 OAuth 回调，刷新当前用户
    await fetchCurrentUser();
  }
};
