// ==================== 世界书获取（角色绑定） ====================
/**
 * 获取当前角色绑定的世界书
 * @param type 'current' 优先获取角色绑定世界书，'global' 获取全局世界书
 * @throws 如果没有找到世界书则抛出错误
 */
export const getCurrentWorldbook = (type: 'current' | 'global'): { primary: string; secondary: string[] } => {
  // 使用酒馆助手提供的接口直接获取角色绑定的世界书
  const charWorldbooks = getCharWorldbookNames('current');
  if (!charWorldbooks) {
    throw new Error('未找到任何世界书，请先在酒馆中创建世界书');
  }

  if (type === 'global') {
    const globalWbs = getGlobalWorldbookNames();
    if (!globalWbs || globalWbs.length === 0) {
      throw new Error('未找到任何全局世界书，请先在酒馆中创建世界书');
    }
    return { primary: globalWbs[0], secondary: globalWbs.slice(1) };
  }

  // current 类型：必须使用角色绑定的世界书
  if (!charWorldbooks.primary) {
    throw new Error('当前角色卡未绑定世界书，请先在角色卡设置中绑定一个世界书');
  }

  return {
    primary: charWorldbooks.primary,
    secondary: (charWorldbooks as any).additional || [],
  };
};

/**
 * 获取世界书的所有条目
 * @param worldbookName 世界书名称
 * @returns 世界书条目数组
 */
export const getWorldbookEntries = async (worldbookName: string): Promise<any[]> => {
  return await getWorldbook(worldbookName);
};

export const deleteWorldbookEntries = async (
  worldbookName: string,
  predicate: (entry: any) => boolean,
  options?: { render?: 'debounced' | 'immediate' },
): Promise<{ worldbook: any[]; deleted_entries: any[] }> => {
  return await (window as any).deleteWorldbookEntries(worldbookName, predicate, options);
};

