// ==================== 通用世界书条目部署函数 ====================
/**
 * 通用世界书条目部署函数
 * 检测是否有同名条目，有则覆盖，无则新增
 * @param worldbookName 世界书名称
 * @param entryName 条目名称
 * @param entryConfig 条目配置
 * @param content 条目内容
 * @param projectName 项目名称（用于标识所属项目，便于后续检索和卸载）
 */
export const deployWorldbookEntry = async (
  worldbookName: string,
  entryName: string,
  entryConfig: Record<string, any>,
  content: string,
  projectName?: string,
): Promise<void> => {
  await updateWorldbookWith(worldbookName, (entries: any[]) => {
    // 检测是否有同名条目，有则覆盖，无则新增
    const existingIndex = entries.findIndex(e => (e.name || e.comment || '') === entryName);

    // 转换配置为符合 Tavern Helper 要求的格式
    const convertedConfig: any = {
      name: entryName,
      enabled: entryConfig.enabled ?? true,
      strategy: {
        type: entryConfig.constant ? 'constant' : entryConfig.selective ? 'selective' : 'vectorized',
        keys: entryConfig.key || [],
        keys_secondary: {
          logic: entryConfig.selectiveLogic === 0 ? 'and_any' : 'and_all',
          keys: entryConfig.keysecondary || [],
        },
        scan_depth: entryConfig.scanDepth || 'same_as_global',
      },
      position: {
        type: 'at_depth' as const,
        depth: entryConfig.depth || 4,
        order: entryConfig.displayIndex || 0,
        role: entryConfig.role || 'system',
      },
      recursion: {
        prevent_incoming: entryConfig.excludeRecursion || false,
        prevent_outgoing: entryConfig.preventRecursion || true,
        delay_until: entryConfig.delayUntilRecursion ? 1 : null,
      },
      effect: {
        sticky: entryConfig.sticky || null,
        cooldown: entryConfig.cooldown || null,
        delay: entryConfig.delay || null,
      },
      probability: entryConfig.useProbability ? entryConfig.probability || 100 : 100,
      content,
      comment: entryConfig.comment || entryName,
    };

    // 如果提供了项目名称，存储到 extra 字段中
    if (projectName) {
      convertedConfig.extra = {
        ...(entries[existingIndex]?.extra || {}),
        fate_project_name: projectName,
      };
    }

    if (existingIndex !== -1) {
      // 存在同名条目，覆盖它
      entries[existingIndex] = {
        ...entries[existingIndex],
        ...convertedConfig,
        uid: entries[existingIndex].uid,
      };
    } else {
      // 不存在，新增条目
      entries.push(convertedConfig);
    }
    return entries;
  });
};
